import {useState} from "react";
import "./style.css";
function Popup({close,onsave}) {
    const [form,setForm] = useState({
        name:"",
        date:"",
        class:"",
        mark:""
    });
    const [errors,setErrors] = useState({});
    // 🔹 handle change
    const handleChange = (e) => {
        const {name,value} = e.target;
        setForm(prev => ({
            ...prev,
            [name]:value
        }));
    };
    // 🔹 validate
    const validate = () => {
        const newErrors = {};
        if (!form.name) newErrors.name = "Tên không được để trống";
        if (!form.date) newErrors.date = "Ngày sinh không được để trống";
        if (!form.class) newErrors.class = "Lớp không được để trống";
        if (!form.mark) newErrors.mark = "Điểm không được để trống";
        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    return(
        <>
            <div className="popup">
                <div className="title">
                    <h2>Thêm học sinh</h2>
                    <button className="close-button" onClick={() => {
                        close();
                        onsave();
                    }}>
                        ×
                    </button>
                </div>
                <form className="form">
                
                    <div className="box">
                        <input
                            name="name"
                            placeholder="Nhập tên"
                            value={form.name}
                            onChange={handleChange}
                        />
                        <span className="error"></span>
                    </div>
                    <div className="box">
                        <input
                            name="date"
                            placeholder="Nhập ngày sinh"
                            value={form.date}
                            onChange={handleChange}
                        />
                        <span className="error"></span>
                    </div>
                    <div className="box">
                        <input
                            name="class"
                            placeholder="Nhập lớp"
                            value={form.class}
                            onChange={handleChange}
                        />
                        <span className="error"></span>
                    </div>
                    <div className="box">
                        <input
                            name="mark"
                            placeholder="Nhập điểm"
                            value={form.mark}
                            onChange={handleChange}
                        />
                        <span className="error"></span>
                    </div>
                    <div className="actions">
                        <button className="btn btn-submit" onClick={
                            (e) => {
                                e.preventDefault();
                                if (validate()) {
                                    onsave();
                                }
                            }}>
                            Submit
                        </button>
                    </div>
                </form>
            </div>
        </>
    )
}
export default Popup;
